import json
import os

import cv2
import numpy as np


class PandoraFrame:
    """One frame: RGB (BGRA, 1920x1080), depth (uint16 mm, 512x424), annotations."""

    def __init__(self, root, index):
        stem = f"{index:06d}"

        rgba = cv2.imread(os.path.join(root, "RGB", f"{stem}_RGB.png"),
                          cv2.IMREAD_UNCHANGED)
        self.rgb = cv2.cvtColor(rgba, cv2.COLOR_BGRA2RGB)

        # IMREAD_UNCHANGED keeps the real 16-bit millimetre values.
        # (Normal imread would crush them to 8-bit -> the "all black" you saw.)
        self.depth_mm = cv2.imread(os.path.join(root, "DEPTH", f"{stem}_DEPTH.png"),
                                   cv2.IMREAD_UNCHANGED)

        with open(os.path.join(root, "data.json")) as fp:
            ann = json.load(fp)
        rec = next(r for r in ann if r["frame_num"] == index)
        self.joints2d = np.array(rec["joints"], dtype=np.float64)    # (J, 2) depth pixels
        self.joints3d = np.array(rec["joints3D"], dtype=np.float64)  # (J, 3) metres, cam frame


def backproject(depth_mm, K):
    """Depth image -> 3D point cloud in the camera frame (metres).

    Camera model (derived from this dataset, reprojection error < 0.1 px):
        u = fx * X/Z + cx
        v = fy * (-Y/Z) + cy     (image y points down, world y points up)
    so the inverse is:
        Z = depth/1000;  X = (u-cx)/fx * Z;  Y = -(v-cy)/fy * Z
    Returns (P, 3).
    """
    vs, us = np.where(depth_mm > 0)                    # skip the 0 = no-measurement pixels
    z = depth_mm[vs, us].astype(np.float64) / 1000.0
    x = (us - K["cx"]) / K["fx"] * z
    y = -(vs - K["cy"]) / K["fy"] * z
    return np.stack([x, y, z], axis=1)


def crop_head(points, head_center, radius=0.13):
    """Keep only points within `radius` metres of the head -> the face cloud."""
    d = np.linalg.norm(points - head_center, axis=1)
    return points[d < radius]


def keep_front(points, slab=0.10):
    """Keep only the front-most surface (the face), dropping neck / sides.

    The face is the closest surface to the camera, so we keep points whose
    depth is within `slab` metres of the nearest point.
    """
    z_near = points[:, 2].min()
    return points[points[:, 2] < z_near + slab]


def head_center(frame):
    """Estimate the 3D head centre from the skeleton joints (metres).

    The upper joints (largest Y = highest up) sit at the head; we take their
    mean and nudge slightly down towards the face. Good enough to seed the fit.
    """
    j = frame.joints3d
    top = j[np.argsort(j[:, 1])[-2:]]      # two highest joints
    c = top.mean(axis=0)
    c[1] -= 0.04                           # move a bit down towards the face centre
    return c
